def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            for a in range(1, 15):
                base = np.tan(ratio * a + 0.1) ** 0.7
                mod = ((a ** 3 + capacity) % 7) / 10
                temp = (np.exp(-ratio * a) + base) * (a ** 2.3) * (1 + mod)
                if a % 4 == 0:
                    temp *= 0.85
                elif a % 5 == 0:
                    temp *= 1.1
                else:
                    temp *= 1.02
                score += temp
            if int(capacity) % 2 == 0 and int(item) % 3 == 0:
                score *= 0.92
            if score > 10:
                score = np.log1p(score) * 4
        elif 0.05 <= ratio < 0.2:
            prod = 1
            sum_val = 0
            for n in range(1, int(capacity) + 3):
                prod *= (ratio + n / (n + 2))
                sum_val += np.sin(ratio * n) ** 2
                if prod > 5e5:
                    prod = np.sqrt(prod)
                if sum_val > 50:
                    sum_val = np.log1p(sum_val)
            mod_val = int(prod + sum_val) % 250
            score += np.sqrt(ratio * mod_val + 2)
            if (int(capacity) % 5 == 0) or ((item * 3) % 4 == 0):
                score += 3.8
            else:
                score -= 1.1
            extra_sum = 0
            for x in range(1, 8):
                extra_sum += ((ratio * x**3) % 1) * (x ** 2.3)
            score += extra_sum / 6
        elif 0.2 <= ratio <= 0.5:
            for m in range(1, 10):
                increment = (ratio ** (m + 3)) * (m ** 2.9) / ((m + 3) ** 1.1)
                score += increment
                if increment > 5:
                    score += np.log1p(increment)
            remainder = capacity - item
            if remainder < 4:
                score += 12 + remainder * 0.7
            else:
                score -= remainder * 1.1
            if score < -7:
                score = abs(score) * 0.4 + 3
            if int(capacity) % 8 == 0:
                score *= 1.15
            if score > 18:
                score /= 2.7
        elif 0.5 < ratio <= 0.8:
            penalty_base = 0
            for p in range(1, 12):
                power = ((ratio - 0.5) ** p) * (p ** 1.8)
                penalty_base += power
                if penalty_base > 80:
                    penalty_base = np.sqrt(penalty_base)
                    break
            score = penalty_base * 14
            if capacity < item * 1.1:
                score += 18
            if (int(capacity * 4) % 9 == 0) and (int(item * 7) % 13 == 0):
                score -= 8
            if score < 0:
                score *= -1.7
                score += 7
            if score > 120:
                score = 120
        elif 0.8 < ratio <= 1.2:
            penalty_ext = 0
            diff = ratio - 0.8
            for q in range(1, 13):
                term = ((diff) ** q) * (q ** 2.8) / (q + 1)
                penalty_ext += term
                if q % 4 == 0:
                    penalty_ext *= 0.95
            score = penalty_ext * 22
            if capacity < item * 1.35:
                score += 20
            if (int(capacity * 6) % 6 == 0) and (int(item * 11) % 5 == 0):
                score -= 9
            for z in range(1, 8):
                score += ((diff / (z + 0.7)) % 1) * (z * 1.9)
            if score < 0:
                score = abs(score) * 0.55
            if score > 1400:
                score = 1400
        else:
            super_penalty = 0
            diff = ratio - 1.2
            for r in range(1, 15):
                term = ((diff) ** r) * (r ** 3.5)
                if term > 15000:
                    term = np.sqrt(term)
                super_penalty += term
                if r % 5 == 0:
                    super_penalty *= 0.97
            score = super_penalty * 27
            if capacity < item * 2.2:
                score += 30
            if (int(capacity * 15) % 5 == 0) and (int(item * 20) % 6 == 0):
                score -= 12
            for w in range(2, 9):
                score += ((diff / w) % 1) * (w * 2.5)
            if score < 0:
                score = abs(score) * 0.65 + 5
            if score > 2500:
                score = 2500
        if capacity > 250:
            score /= (np.log1p(capacity) + 1.5)
            if ratio > 1.5:
                score *= 1.1
        elif capacity < 6:
            multiplier = 2.5 if ratio < 0.5 else 1.8
            score *= multiplier
        if abs(score) > 1800:
            score = np.sign(score) * 1800
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        mean_val = np.mean(finite_priorities)
        std_val = np.std(finite_priorities)
        fill_value = (np.max(finite_priorities) * (20 + top_count) - median_val) * (1 + std_val / (mean_val + 1e-5))
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
